/// Returns the configured [FeedbackBackend].
///
/// Call [backend.dispose()] when the owning widget is disposed.
FeedbackBackend createFeedbackBackend() {
{{#webhook}}
  return WebhookBackend(
    url: '{{webhook_url}}',
  );
{{/webhook}}
{{#firebase}}
  // Ensure Firebase.initializeApp() has been called before using this backend.
  return FirebaseFeedbackBackend(
    collection: 'feedback',
    // screenshotsBucket: 'feedback-screenshots', // uncomment to upload screenshots to Storage
  );
{{/firebase}}
{{#linear}}
  return LinearFeedbackBackend(
    // apiKey: 'YOUR_LINEAR_API_KEY', // load from remote config — never hard-code
    // teamId: 'YOUR_TEAM_ID',
  );
{{/linear}}
}

