/// Middleware pipeline — [AiCategorizationMiddleware] auto-suggests a category
/// using Claude. Pass the Anthropic API key via --dart-define or load it from
/// remote config at runtime. Never embed the key in source.
List<FeedbackMiddleware> createMiddlewares() {
  return [
    AiCategorizationMiddleware(
      apiKey: const String.fromEnvironment('ANTHROPIC_API_KEY'),
    ),
  ];
}
{{/use_ai_categorization}}
{{^use_ai_categorization}}
