class HomeScreen extends StatefulWidget {
  const HomeScreen({super.key});

  @override
  State<HomeScreen> createState() => _HomeScreenState();
}

class _HomeScreenState extends State<HomeScreen> {
  late final FeedbackBackend _backend;

  @override
  void initState() {
    super.initState();
    _backend = createFeedbackBackend();
  }

  @override
  void dispose() {
    _backend.dispose();
    super.dispose();
  }

{{#use_ai_categorization}}
  // FeedbackWidget is used directly so middlewares can be supplied.
  Future<void> _openFeedback() async {
    await showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      builder: (_) => Padding(
        padding: EdgeInsets.fromLTRB(
          16,
          16,
          16,
          MediaQuery.of(context).viewInsets.bottom + 16,
        ),
        child: FeedbackWidget(
          backend: _backend,
          appVersion: '{{app_version}}',
          metadataCollector: FeedbackMetadataCollector(),
          middlewares: createMiddlewares(),
          showRating: true,
          onSuccess: () {
            Navigator.pop(context);
            debugPrint('[FeedbackKit] Submitted');
          },
          onError: (e) => debugPrint('[FeedbackKit] Error: $e'),
        ),
      ),
    );
  }
{{/use_ai_categorization}}

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('My App')),
      body: const Center(child: Text('Your app content here')),
{{#use_ai_categorization}}
      floatingActionButton: FloatingActionButton.extended(
        onPressed: _openFeedback,
        icon: const Icon(Icons.feedback_outlined),
        label: const Text('Feedback'),
      ),
{{/use_ai_categorization}}
{{^use_ai_categorization}}
      floatingActionButton: FeedbackButton(
        backend: _backend,
        appVersion: '{{app_version}}',
        metadataCollector: FeedbackMetadataCollector(),
